INSERT INTO `diagnoses` VALUES (1,2,2,'2026-03-17 16:00:00',NULL,'MRI','肺癌','IV期','经头部磁共振成像（MRI）及病理活检确诊为脑胶质母细胞瘤，肿瘤位于右侧额叶，占位效应明显，压迫周围脑组织及血管。患者目前存在头痛、呕吐、视力模糊等颅内压增高症状，偶有肢体抽搐发作。','手术治疗：尽快安排开颅肿瘤切除术，尽可能切除肿瘤组织，缓解颅内压，明确病理分型。\r\n\r\n放射治疗：术后辅以全脑及局部肿瘤床的放射治疗，抑制肿瘤细胞生长，降低复发风险。\r\n\r\n化学治疗：采用替莫唑胺等化疗药物进行同步放化疗及后续辅助化疗，进一步杀灭残留肿瘤细胞。\r\n\r\n对症支持治疗：针对患者的头痛、呕吐等症状给予相应药物缓解，同时注意维持患者营养状况、水电解质平衡等。','头部 MRI 提示右侧额叶占位性病变，考虑恶性肿瘤可能性大。\r\n\r\n病理报告：胶质母细胞瘤 WHO Ⅳ级。\r\n\r\n血常规、肝肾功能等实验室检查基本正常，无明显手术及放化疗禁忌。','尽快治疗','2026-03-09 15:30:24'),(3,3,1,'2026-04-05 16:00:00',NULL,'MRI','脑转移瘤（肺腺癌来源）','IV期','头部MRI增强扫描示：左侧基底节区及右额叶皮层下可见两处类圆形环状强化灶，中心呈长T1长T2信号，周围伴明显大片状血管源性脑水肿，占位效应显著。结合胸部CT结果，高度怀疑脑转移瘤。\r\n','1. 脱水降颅压（甘露醇 125ml q8h + 地塞米松 10mg qd）；2. 完善肺部穿刺活检明确病理；3. 待全身状况稳定后，考虑行全脑放疗（WBRT）或立体定向放射外科（SRS）；4. 多学科会诊制定全身化疗方案。','MRI提示颅内多发转移瘤。肺部CT示左肺下叶占位，考虑恶性。头颅MRA未见明显血管畸形。',' 患者处于卒中样起病，需密切监测颅内压变化，警惕脑疝形成。建议家属签署病危通知书。','2026-04-06 09:44:22'),(4,4,1,'2026-04-05 16:00:00',NULL,'MRI',' 脑膜瘤','I期',' 头部MRI平扫+增强示：左侧岩斜区可见一类圆形等T1等T2信号占位，边界清晰，呈宽基底与硬脑膜相连，增强扫描呈明显均匀强化，局部包绕左侧颈内动脉，周围脑组织轻度受压，水肿不明显。','1. 完善术前评估（包括脑血管造影或CTA评估肿瘤供血及血管受累情况）；2. 择期行显微镜下肿瘤切除术；3. 术后病理明确分型；4. 定期随访复查MRI。','MRI提示左侧岩斜区脑膜瘤（WHO I级征象）。血常规、凝血功能、心电图未见明显异常肿瘤位置深在，毗邻重要颅底血管神经（动眼神经、三叉神经），手术难度较高，需注意术后脑脊液漏及颅神经损伤风险。。','肿瘤位置深在，毗邻重要颅底血管神经（动眼神经、三叉神经），手术难度较高，需注意术后脑脊液漏及颅神经损伤风险。','2026-04-06 12:49:45'),(5,5,1,'2026-04-09 16:00:00',NULL,'MRI','低级别胶质瘤','II期','头部MRI平扫+增强示：左侧颞叶皮层及皮层下可见片状稍长T1稍长T2信号影，FLAIR序列呈高信号，边界欠清，增强扫描未见明显强化，周围轻度水肿，局部脑沟变浅。\r\n',' 1. 完善长程视频脑电图监测；2. 行癫痫病灶定位评估；3. 择期行开颅肿瘤切除术（病灶切除术）；4. 术后根据病理结果决定是否行放化疗；5. 长期口服抗癫痫药物（如丙戊酸钠）预防发作。\r\n','MRI提示左侧颞叶低级别胶质瘤可能性大。脑电图提示左侧颞区棘慢波发放。','患者年轻男性，以癫痫为首发症状，病灶位于非功能区，手术指征明确，建议术中唤醒或导航下精准切除。','2026-04-10 15:52:34'),(6,6,1,'2026-04-10 16:00:00',NULL,'MRI','脑膜瘤（凸面）','I期','头部MRI平扫+增强示：右侧额叶凸面可见一类圆形占位性病变，大小约2.8cm×2.5cm，呈等T1等T2信号，边界清晰，增强扫描呈明显均匀强化，可见“脑膜尾征”，周围脑组织受压，伴轻度脑水肿。\r\n','1. 完善术前常规检查（心电图、胸片、凝血功能）；2. 择期行显微镜下肿瘤切除术；3. 术后给予抗水肿治疗（甘露醇脱水）；4. 定期随访复查MRI观察有无复发。',' MRI提示右侧额叶脑膜瘤（WHO I级）。血常规、肝肾功能未见明显异常。','肿瘤位于非功能区，手术预后较好，但需注意术后皮瓣下积液及颅内感染风险。','2026-04-11 11:08:43');
/*!40000 ALTER TABLE `diagnoses` ENABLE KEYS */;
