INSERT INTO `patient_clinical_info` VALUES (1,2,'反复咳嗽、咯血伴胸痛 2 月余。','患者 2 月前无明显诱因出现咳嗽，为阵发性干咳，偶有少量白色黏痰，未予重视。1 月前开始出现咯血，为痰中带血丝，量不多，约每日 1 - 2 次，每次约 2 - 3 口，同时伴有左侧胸部隐痛，呈间歇性，活动后加重，休息后可缓解。无发热、盗汗，无呼吸困难、胸闷、气促等症状。曾于外院就诊，行胸部 X 线检查提示左肺占位性病变，遂转至我院进一步诊治。自发病以来，患者精神状态尚可，食欲稍减退，睡眠一般，体重下降约 5kg。\r\n','- 否认高血压、糖尿病、心脏病等慢性病史。\r\n- 否认肝炎、结核等传染病史。\r\n- 无手术、外伤史。\r\n- 无输血史。\r\n- 无药物及食物过敏史。\r\n','父亲因肺癌去世，母亲健在，家族中无其他恶性肿瘤病史。\r\n','无',1,1,0,0,0,1,NULL,'2026-03-10 15:23:43','2026-03-18 15:36:41'),(2,3,'突发右侧肢体无力伴言语不清3小时','患者于今日早餐时突发右侧肢体无力，持筷不稳，继而跌倒，伴口齿不清、口角歪斜，无恶心呕吐，无意识丧失。急送至我院急诊，行头颅CT示左侧基底节区低密度灶，遂收住入院。','高血压病史5年，最高血压160/100mmHg，自服“氨氯地平”控制，血压波动较大。否认糖尿病及冠心病史。\r\n','父亲有脑卒中病史，母亲健在。','青霉素过敏（皮疹）。',1,0,0,0,0,1,NULL,'2026-04-06 09:42:51','2026-04-06 09:42:51'),(3,4,'反复头晕、头痛伴视物重影2周','患者近2周无明显诱因出现持续性钝痛，以晨起为重，伴头晕、行走不稳，自觉视物成双。无恶心呕吐，无肢体抽搐。自行服用止痛药效果不佳，为进一步诊治来院。','体健，否认高血压、糖尿病史。否认肝炎结核病史。','母亲有高血压病史，否认家族遗传性疾病史。\r\n','无药物及食物过敏史。',1,0,0,0,0,0,NULL,'2026-04-06 12:48:33','2026-04-06 12:48:33'),(4,5,'发作性意识丧失伴四肢抽搐1月，加重2次。\r\n','患者近1个月来无明显诱因出现3次突发意识丧失，伴双眼上翻、口吐白沫、四肢强直阵挛，每次持续约2-3分钟，发作后伴有嗜睡。发作间期神志清醒，无不适。外院头颅CT未见明显出血，为求进一步诊治收入院。','出生时曾有轻度窒息史，余无特殊。否认高血压、心脏病史。','否认癫痫及精神疾病家族史。','否认药物及食物过敏史。',0,0,1,0,0,0,NULL,'2026-04-10 15:53:44','2026-04-11 11:12:46'),(5,6,'反复头痛、头晕伴右侧肢体麻木1月余。','患者近1月来无明显诱因逐渐出现头部胀痛，以额颞部为主，呈持续性，晨起及夜间加重，伴有阵发性眩晕。近1周自觉右手持物无力，书写笨拙。无恶心呕吐，无视物模糊，无意识丧失。为进一步诊治就诊。\r\n','患有高血压病史5年，规律服药，控制尚可。否认糖尿病史。','父亲因肺癌去世，否认家族性遗传病史。','青霉素过敏。\r\n',1,0,0,1,0,1,NULL,'2026-04-11 11:07:39','2026-04-11 11:07:39');
/*!40000 ALTER TABLE `patient_clinical_info` ENABLE KEYS */;
UNLOCK TABLES;

